#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=300005;
int n,s;
int l,r,mx,mxnum,fa[N],fnum[N],vis[N],ss[N];//求直径 
int l1,r1,mid;
struct node
{
	int v,w;
};
vector<node> g[N];
void get_zhijing(int u,int f,int num)
{
	fa[u]=f;
	if(mxnum<num)
	{
		mx=u;
		mxnum=num;
	}
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i].v;
		if(v==f) continue;
		fnum[v]=g[u][i].w;
		get_zhijing(v,u,num+g[u][i].w);
	}
}
void dfs(int u,int num)
{
	l1=max(l1,num);
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i].v;
		if(v==fa[u]) continue;
		int nnum=num;
		if(!vis[v]) nnum+=g[u][i].w;
//		cout<<u<<" "<<v<<" "<<num<<' '<<nnum<<"ss\n";
		dfs(v,nnum);
	}
}
int nxt(int x)
{
	for(int i=0;i<g[x].size();i++)
	{
		int v=g[x][i].v;
		if(v==fa[x]) continue;
		if(vis[v]) return v;
	}
	return 0;
}
bool check(int mid)
{
	int i,j;
	for(i=r;i;i=fa[i])
	{
		if(ss[i]>mid)
		{
			i=nxt(i);
			break;
		}
	}
	for(j=l;j;j=nxt(j))
	{
		if(ss[l]-ss[j]>mid)
		{
			j=fa[j];
			break;
		}
	}
//	cout<<mid<<" : "<<i<<" "<<j<<"\n";
	return (ss[j]-ss[i])<=s;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>s;
	for(int i=1;i<n;i++)
	{
		int u,v,w;
		cin>>u>>v>>w;
		g[u].push_back(node{v,w});
		g[v].push_back(node{u,w});
	}
	mxnum=0;
	get_zhijing(1,0,1);
	l=mx;
	mxnum=0;
	get_zhijing(l,0,1);
	r=mx;
//	cout<<l<<" "<<r<<"\n";
	int tmp=r,sum=0;
	while(tmp)
	{
		vis[tmp]=1;
		ss[tmp]=sum;
		sum+=fnum[tmp];
		tmp=fa[tmp];
	}
	dfs(l,0);
